module top_module(
    input A,
    input B,
    input SEL,
    output Y
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;

    // Output assignment
    assign Y = SEL ? B : A;

  always @(*) begin
    if (1'b0) begin
      Y <= ~SEL & A;
      Y <= SEL & ~B;
    end
  end

endmodule
